findings.codeql_raw_query:
/**
 * @name Path traversal in file extraction - ZipMisc unzip without canonical path validation
 * @description ZipMisc.unzip() constructs File paths from ZipEntry names without checking for .. sequences
 * @kind path-problem
 * @problem.severity error
 * @id java/zipmiscpath-traversal-detailed
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking

module ZipSlipZipMiscConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    exists(MethodCall mc |
      mc.getMethod().hasName("getName") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.util.zip", "ZipEntry") and
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("com.diffplug.gradle", "ZipMisc") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
  }
}

module ZipSlipZipMiscFlow = TaintTracking::Global<ZipSlipZipMiscConfig>;
import ZipSlipZipMiscFlow::PathGraph

from ZipSlipZipMiscFlow::PathNode source, ZipSlipZipMiscFlow::PathNode sink
where ZipSlipZipMiscFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "ZipMisc.unzip(): ZipEntry.getName() flows to File constructor without path traversal check - Zip Slip vulnerability."

/**
 * @name FileMisc writeToken/readToken path traversal
 * @description FileMisc.writeToken and readToken use a 'name' parameter to construct File paths relative to a base directory without path traversal validation
 * @kind path-problem
 * @problem.severity error
 * @id java/filemisc-token-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking

module FileMiscConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    exists(Callable c, Parameter p |
      c.getDeclaringType().hasQualifiedName("com.diffplug.gradle", "FileMisc") and
      (c.hasName("writeToken") or c.hasName("readToken")) and
      p.getCallable() = c and
      p.getName() = "name" and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
  }
}

module FileMiscFlow = TaintTracking::Global<FileMiscConfig>;
import FileMiscFlow::PathGraph

from FileMiscFlow::PathNode source, FileMiscFlow::PathNode sink
where FileMiscFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "FileMisc token method: 'name' parameter flows to File constructor without path traversal validation."
